'use client';

import { motion, useScroll, useSpring, useTransform } from 'framer-motion';
import { useEffect, useMemo, useRef, useState } from 'react';

const FRAME_COUNT = 240;

const pad = (value: number) => String(value).padStart(3, '0');

const buildSources = () => Array.from({ length: FRAME_COUNT }, (_, index) => `/sequence/ezgif-frame-${pad(index + 1)}.jpg`);

const scaleCover = (canvas: HTMLCanvasElement, image: HTMLImageElement) => {
  const { width: cw, height: ch } = canvas;
  const { width: iw, height: ih } = image;
  const scale = Math.max(cw / iw, ch / ih);
  const dx = (cw - iw * scale) / 2;
  const dy = (ch - ih * scale) / 2;
  return { width: iw * scale, height: ih * scale, x: dx, y: dy };
};

export default function SequenceScroll() {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imagesRef = useRef<HTMLImageElement[]>([]);
  const [loaded, setLoaded] = useState(false);
  const [preloadProgress, setPreloadProgress] = useState(0);
  const [currentFrame, setCurrentFrame] = useState(0);

  const sources = useMemo(buildSources, []);
  const { scrollYProgress } = useScroll({ target: containerRef, offset: ['start start', 'end end'] });
  const smoothProgress = useSpring(scrollYProgress, { stiffness: 150, damping: 40 });

  const titleOpacity = useTransform(scrollYProgress, [0, 0.12], [1, 0]);
  const leftOpacity = useTransform(scrollYProgress, [0.25, 0.35, 0.45], [0, 1, 0]);
  const rightOpacity = useTransform(scrollYProgress, [0.55, 0.65, 0.75], [0, 1, 0]);
  const ctaOpacity = useTransform(scrollYProgress, [0.85, 0.93], [0, 1]);

  useEffect(() => {
    let loadedCount = 0;

    const imagePromises = sources.map((src) =>
      new Promise<HTMLImageElement>((resolve) => {
        const image = new Image();
        image.src = src;
        image.decode?.().catch(() => undefined);
        image.onload = () => {
          loadedCount += 1;
          setPreloadProgress(Math.round((loadedCount / FRAME_COUNT) * 100));
          resolve(image);
        };
        image.onerror = () => {
          loadedCount += 1;
          setPreloadProgress(Math.round((loadedCount / FRAME_COUNT) * 100));
          resolve(image);
        };
      })
    );

    Promise.all(imagePromises).then((allImages) => {
      imagesRef.current = allImages;
      setLoaded(true);
    });
  }, [sources]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const drawFrame = (frameIndex: number) => {
      const image = imagesRef.current[frameIndex];
      if (!image || !image.complete) return;
      const { width, height, x, y } = scaleCover(canvas, image);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(image, x, y, width, height);
    };

    const resizeCanvas = () => {
      const rect = canvas.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      canvas.width = Math.floor(rect.width * dpr);
      canvas.height = Math.floor(rect.height * dpr);
      canvas.style.width = `${rect.width}px`;
      canvas.style.height = `${rect.height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      if (imagesRef.current.length) drawFrame(currentFrame);
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const unsubscribe = smoothProgress.on('change', (latest) => {
      const frameIndex = Math.min(FRAME_COUNT - 1, Math.max(0, Math.floor(latest * FRAME_COUNT)));
      setCurrentFrame(frameIndex);
      if (imagesRef.current.length) drawFrame(frameIndex);
    });

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      unsubscribe();
    };
  }, [smoothProgress, currentFrame]);

  return (
    <div ref={containerRef} className="relative h-[400vh] bg-[#0f0b08]">
      <div className="sticky top-0 h-screen w-full overflow-hidden">
        <div className="absolute inset-0 bg-[#0f0b08] bg-hero-glow" />
        <canvas ref={canvasRef} className="absolute inset-0 h-full w-full object-cover" />
        <div className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center px-6 text-center">
          <motion.div style={{ opacity: titleOpacity }} className="relative z-10 max-w-3xl">
            <p className="text-sm uppercase tracking-[0.35em] text-amber-200/70">Aromea</p>
            <h1 className="mt-6 text-5xl font-semibold tracking-tight text-white md:text-6xl lg:text-7xl">
              The perfume story that unfolds with every scroll.
            </h1>
            <p className="mt-6 text-lg leading-8 text-stone-300/90 md:text-xl">
              Aromea blends fragrance, motion, and luxury into a sensory journey of scent, emotion, and artistry.
            </p>
          </motion.div>

          <motion.div style={{ opacity: leftOpacity }} className="absolute left-0 top-1/3 w-full px-10 text-left md:px-20">
            <div className="inline-flex rounded-full border border-rose-300/20 bg-black/20 px-5 py-3 text-sm uppercase tracking-[0.3em] text-rose-100/80 backdrop-blur-sm">
              awaken the essence
            </div>
            <p className="mt-6 max-w-xl text-3xl font-medium leading-tight text-white md:text-4xl">
              A slow revelation of top notes, heart, and precious base.
            </p>
          </motion.div>

          <motion.div style={{ opacity: rightOpacity }} className="absolute right-0 top-1/2 w-full px-10 text-right md:px-20">
            <div className="inline-flex rounded-full border border-rose-300/20 bg-black/20 px-5 py-3 text-sm uppercase tracking-[0.3em] text-rose-100/80 backdrop-blur-sm">
              luxe by design
            </div>
            <p className="mt-6 max-w-xl text-3xl font-medium leading-tight text-white md:text-4xl">
              It's not just fragrance. It's poetry on your skin.
            </p>
          </motion.div>

          <motion.div style={{ opacity: ctaOpacity }} className="absolute bottom-14 left-1/2 w-full max-w-lg -translate-x-1/2 px-8 text-center">
            <p className="text-sm uppercase tracking-[0.35em] text-rose-200/80">Discover the fragrance</p>
            <h2 className="mt-4 text-4xl font-semibold tracking-tight text-white md:text-5xl">
              Experience the sensory journey.
            </h2>
            <button className="mt-8 inline-flex items-center justify-center rounded-full border border-rose-200/30 bg-rose-200/10 px-8 py-4 text-base font-semibold tracking-[0.15em] text-rose-100 transition-all duration-300 hover:-translate-y-1 hover:bg-rose-200/15 hover:text-white focus:outline-none">
              Explore perfumes
            </button>
          </motion.div>

          {!loaded && (
            <div className="absolute inset-0 z-20 flex items-center justify-center loader-overlay">
              <div className="rounded-3xl border border-white/10 bg-black/80 p-10 text-center text-white shadow-glow">
                <p className="text-sm uppercase tracking-[0.45em] text-amber-200/80">Loading scene</p>
                <p className="mt-4 text-5xl font-semibold text-white">{preloadProgress}%</p>
                <div className="mt-6 h-2 w-72 overflow-hidden rounded-full bg-white/10">
                  <div className="h-full bg-gradient-to-r from-amber-300 via-amber-200 to-white" style={{ width: `${preloadProgress}%` }} />
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
