'use client';

import { motion, AnimatePresence } from 'framer-motion';
import { useState } from 'react';

const navLinks = ['Home', 'Origins', 'Craft', 'Stories', 'Contact'];
const socialLinks = ['Instagram', 'Dribbble', 'Behance'];

export default function Navbar() {
  const [open, setOpen] = useState(false);

  return (
    <header className="fixed inset-x-0 top-0 z-50 mx-auto flex w-full max-w-7xl items-center justify-between px-6 py-6 md:px-10">
      <div className="relative z-20 flex items-center gap-4 text-white">
        <div className="flex h-12 w-12 items-center justify-center rounded-3xl border border-white/10 bg-[#110b07]/80 text-lg font-semibold text-rose-300 shadow-glow">
          A
        </div>
        <div>
          <p className="text-xs uppercase tracking-[0.5em] text-rose-200/80">Aromea</p>
          <p className="text-sm text-stone-200/80">Fragrance studio</p>
        </div>
      </div>
      <button
        onClick={() => setOpen((state) => !state)}
        className="relative z-20 inline-flex h-12 w-12 items-center justify-center rounded-full border border-white/10 bg-white/5 text-white transition hover:bg-white/10"
        aria-label="Open navigation menu"
      >
        <span className="absolute h-0.5 w-6 rounded-full bg-white transition duration-300" />
        <span className="absolute h-0.5 w-6 rounded-full bg-white transition duration-300 [transform:translateY(6px)]" />
        <span className="absolute h-0.5 w-6 rounded-full bg-white transition duration-300 [transform:translateY(-6px)]" />
      </button>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, scale: 0.96 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.96 }}
            className="fixed inset-0 z-40 overflow-hidden bg-[#0f0b08]/95 backdrop-blur-xl"
          >
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,_rgba(255,195,120,0.18),_transparent_30%)]" />
            <div className="relative mx-auto flex h-full max-w-6xl flex-col justify-center px-8 py-12 text-white md:px-14">
              <button
                onClick={() => setOpen(false)}
                className="self-end rounded-full border border-white/10 bg-white/5 px-4 py-3 text-sm uppercase tracking-[0.25em] text-white transition hover:bg-white/10"
              >
                Close
              </button>
              <nav className="mt-16 grid gap-10">
                {navLinks.map((link, index) => (
                  <motion.a
                    key={link}
                    href={`#${link.toLowerCase()}`}
                    whileHover={{ x: 10 }}
                    className="text-[clamp(3rem,7vw,5.5rem)] font-semibold uppercase tracking-[-0.03em] text-white"
                    style={{ transitionDelay: `${index * 60}ms` }}
                  >
                    {link}
                  </motion.a>
                ))}
              </nav>
              <div className="mt-auto grid gap-6 border-t border-white/10 pt-12 text-sm text-stone-300">
                <div className="grid gap-2">
                  <span className="uppercase tracking-[0.35em] text-amber-200/80">Social</span>
                  <div className="flex flex-wrap gap-4">
                    {socialLinks.map((social) => (
                      <a key={social} href="#" className="transition hover:text-amber-200">
                        {social}
                      </a>
                    ))}
                  </div>
                </div>
                <div className="grid gap-2">
                  <span className="uppercase tracking-[0.35em] text-amber-200/80">Contact</span>
                  <p>hello@aromea.coffee</p>
                  <p>+1 555 018 974</p>
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
}
